import React from 'react';
import { useFetch } from './useFetch';
import './styles.css';

interface User {
  id: number;
  name: string;
  email: string;
}

export default function App() {
  const { data, loading, error, refetch } = useFetch<User>(
    'https://jsonplaceholder.typicode.com/users/1'
  );

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>useFetch</h1>
      {loading && <p data-testid="loading" className="fetch-loading">Loading…</p>}
      {error && <p data-testid="error" className="fetch-error">{error}</p>}
      {data && (
        <div data-testid="data" className="fetch-card">
          <h2>{data.name}</h2>
          <p>{data.email}</p>
        </div>
      )}
      <button data-testid="refetch" className="fetch-btn" onClick={refetch}>
        Refetch
      </button>
    </div>
  );
}

import { useState, useEffect } from 'react';

interface UseFetchReturn<T> {
  data: T | null;
  loading: boolean;
  error: string | null;
  refetch: () => void;
}

/**
 * Custom hook that fetches JSON data from a URL.
 *
 * @param url - The endpoint to fetch
 * @returns Object containing data, loading, error, and a refetch function
 */
export function useFetch<T>(url: string): UseFetchReturn<T> {
  // TODO: Set up state for data, loading, error
  // TODO: Use useEffect to fetch data when url changes
  // TODO: Implement AbortController for cancellation
  // TODO: Implement refetch as a way to re-trigger the effect

  return {
    data: null,
    loading: false,
    error: null,
    refetch: () => {},
  };
}

.fetch-loading {
  color: #6b7280;
  font-style: italic;
}

.fetch-error {
  color: #ef4444;
  padding: 0.75rem;
  background: #fef2f2;
  border: 1px solid #fecaca;
  border-radius: 0.375rem;
}

