import { render, screen, fireEvent, waitFor } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { useFetch } from './useFetch';

const MOCK_USER = { id: 1, name: 'Alice', email: 'alice@example.com' };

function Harness({ url }: { url: string }) {
  const { data, loading, error, refetch } = useFetch<typeof MOCK_USER>(url);
  return (
    <div>
      {loading && <span data-testid="loading">Loading</span>}
      {error && <span data-testid="error">{error}</span>}
      {data && <span data-testid="data">{data.name}</span>}
      <button data-testid="refetch" onClick={refetch}>Refetch</button>
    </div>
  );
}

describe('useFetch', () => {
  beforeEach(() => {
    global.fetch = jest.fn();
  });

  afterEach(() => {
    jest.restoreAllMocks();
  });

  it('shows loading state initially', () => {
    (global.fetch as jest.Mock).mockReturnValue(new Promise(() => {}));
    render(<Harness url="/api/user" />);
    expect(screen.getByTestId('loading')).toBeInTheDocument();
  });

  it('shows data on successful fetch', async () => {
    (global.fetch as jest.Mock).mockResolvedValue({
      ok: true,
      json: async () => MOCK_USER,
    });
    render(<Harness url="/api/user" />);
    await waitFor(() => {
      expect(screen.getByTestId('data')).toHaveTextContent('Alice');
    });
    expect(screen.queryByTestId('loading')).not.toBeInTheDocument();
  });

  it('shows error on failed fetch', async () => {
    (global.fetch as jest.Mock).mockResolvedValue({
      ok: false,
      status: 500,
      statusText: 'Internal Server Error',
    });
    render(<Harness url="/api/user" />);
    await waitFor(() => {
      expect(screen.getByTestId('error')).toBeInTheDocument();
    });
    expect(screen.queryByTestId('data')).not.toBeInTheDocument();
  });

  it('shows error on network failure', async () => {
    (global.fetch as jest.Mock).mockRejectedValue(new Error('Network error'));
    render(<Harness url="/api/user" />);
    await waitFor(() => {
      expect(screen.getByTestId('error')).toHaveTextContent('Network error');
    });
  });

  it('refetch triggers a new request', async () => {
    let callCount = 0;
    (global.fetch as jest.Mock).mockImplementation(async () => {
      callCount++;
      return { ok: true, json: async () => ({ ...MOCK_USER, name: `User ${callCount}` }) };
    });
    render(<Harness url="/api/user" />);
    await waitFor(() => {
      expect(screen.getByTestId('data')).toHaveTextContent('User 1');
    });
    fireEvent.click(screen.getByTestId('refetch'));
    await waitFor(() => {
      expect(screen.getByTestId('data')).toHaveTextContent('User 2');
    });
  });
});

